// src/data/bookingStore.js
import { MOCK_BOOKINGS } from './mockBookings.js';

const STORAGE_KEY = 'mizuya_bookings';

function seedIfEmpty() {
  if (!localStorage.getItem(STORAGE_KEY)) {
    localStorage.setItem(STORAGE_KEY, JSON.stringify(MOCK_BOOKINGS));
  }
}

export function getBookings() {
  seedIfEmpty();
  try {
    return JSON.parse(localStorage.getItem(STORAGE_KEY)) || [];
  } catch {
    return [];
  }
}

export function addBooking(booking) {
  const all = getBookings();
  all.unshift(booking);
  localStorage.setItem(STORAGE_KEY, JSON.stringify(all));
}

export function updateBooking(id, patch) {
  const all = getBookings().map(b => b.id === id ? { ...b, ...patch } : b);
  localStorage.setItem(STORAGE_KEY, JSON.stringify(all));
  return all;
}

export function generateRefCode() {
  return 'MZ-' + Math.random().toString(36).slice(2, 7).toUpperCase();
}

// ─── Date utilities ───────────────────────────────────────────────────────────

// Accepts either toDateStr(year, month, day)  ← Calendar.jsx style
//             or toDateStr(dateObject)         ← legacy style
export function toDateStr(yearOrDate, month, day) {
  let y, m, d;
  if (typeof yearOrDate === 'number') {
    y = yearOrDate;
    m = month;
    d = day;
  } else {
    const dt = yearOrDate;
    y = dt.getFullYear();
    m = dt.getMonth();
    d = dt.getDate();
  }
  return `${y}-${String(m + 1).padStart(2, '0')}-${String(d).padStart(2, '0')}`;
}

export function formatDate(dateStr) {
  if (!dateStr) return '';
  const date = new Date(dateStr + 'T00:00:00');
  return date.toLocaleDateString('en-PH', {
    weekday: 'short',
    year: 'numeric',
    month: 'short',
    day: 'numeric',
  });
}

export function diffDays(dateStr1, dateStr2) {
  const a = new Date(dateStr1 + 'T00:00:00');
  const b = new Date(dateStr2 + 'T00:00:00');
  return Math.round((b - a) / (1000 * 60 * 60 * 24));
}

export function isWeekend(dateStr) {
  if (!dateStr) return false;
  const day = new Date(dateStr + 'T00:00:00').getDay();
  return day === 5 || day === 6 || day === 0; // Fri, Sat, Sun
}

// Philippine public holidays 2025–2026
const PH_HOLIDAYS = new Set([
  '2025-01-01','2025-04-09','2025-04-17','2025-04-18',
  '2025-05-01','2025-06-12','2025-08-25','2025-11-01',
  '2025-11-30','2025-12-08','2025-12-25','2025-12-30','2025-12-31',
  '2026-01-01','2026-04-09','2026-04-02','2026-04-03',
  '2026-05-01','2026-06-12','2026-08-31','2026-11-01',
  '2026-11-30','2026-12-08','2026-12-25','2026-12-30','2026-12-31',
]);

export function isHoliday(dateStr) {
  return PH_HOLIDAYS.has(dateStr);
}

// ─── isBooked — checks localStorage bookings for date conflicts ───────────────
export function isBooked(dateStr) {
  const bookings = getBookings();
  return bookings.some(b => {
    if (b.status === 'cancelled') return false;
    if (b.bookingType === 'day-use') {
      return b.checkIn === dateStr;
    }
    // overnight: block checkIn up to (not including) checkOut
    return dateStr >= b.checkIn && dateStr < b.checkOut;
  });
}

export const BOOKED_DATES = [];
